use std::collections::HashMap;
use std::sync::{Arc, Mutex};
use std::thread;

#[derive(Debug, Clone)]
pub struct InventorySystem {
    stock: Arc<Mutex<HashMap<String, u64>>>,
}

#[derive(Debug, Clone, PartialEq)]
pub enum InventoryError {
    ItemNotFound(String),
    InsufficientStock { item: String, available: u64, requested: u64 },
    LockPoisoned,
}

impl std::fmt::Display for InventoryError {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        match self {
            InventoryError::ItemNotFound(item) => write!(f, "Item not found: {}", item),
            InventoryError::InsufficientStock { item, available, requested } => {
                write!(f, "Insufficient stock for '{}': available={}, requested={}", item, available, requested)
            }
            InventoryError::LockPoisoned => write!(f, "Internal error: lock poisoned"),
        }
    }
}

impl InventorySystem {
    pub fn new() -> Self {
        InventorySystem {
            stock: Arc::new(Mutex::new(HashMap::new())),
        }
    }

    pub fn add_item(&self, item: &str, quantity: u64) -> Result<(), InventoryError> {
        let mut stock = self.stock.lock().map_err(|_| InventoryError::LockPoisoned)?;
        let entry = stock.entry(item.to_string()).or_insert(0);
        *entry = entry.checked_add(quantity).unwrap_or(u64::MAX);
        Ok(())
    }

    pub fn get_stock(&self, item: &str) -> Result<u64, InventoryError> {
        let stock = self.stock.lock().map_err(|_| InventoryError::LockPoisoned)?;
        stock.get(item).copied().ok_or_else(|| InventoryError::ItemNotFound(item.to_string()))
    }

    /// Atomically checks stock level and decrements inventory.
    /// The check and decrement happen within a single lock acquisition,
    /// preventing TOCTOU race conditions where two threads could both
    /// see sufficient stock and both decrement, leading to overselling.
    pub fn purchase(&self, item: &str, quantity: u64) -> Result<u64, InventoryError> {
        let mut stock = self.stock.lock().map_err(|_| InventoryError::LockPoisoned)?;

        let current = stock
            .get(item)
            .copied()
            .ok_or_else(|| InventoryError::ItemNotFound(item.to_string()))?;

        if current < quantity {
            return Err(InventoryError::InsufficientStock {
                item: item.to_string(),
                available: current,
                requested: quantity,
            });
        }

        let new_quantity = current - quantity;
        stock.insert(item.to_string(), new_quantity);
        Ok(new_quantity)
    }

    /// Atomically purchase multiple items. Either all items are decremented
    /// or none are (transactional semantics). The entire operation holds the
    /// lock so no partial updates are visible to other threads.
    pub fn purchase_multiple(&self, items: &[(&str, u64)]) -> Result<HashMap<String, u64>, InventoryError> {
        let mut stock = self.stock.lock().map_err(|_| InventoryError::LockPoisoned)?;

        // First pass: validate all items have sufficient stock
        for &(item, quantity) in items {
            let current = stock
                .get(item)
                .copied()
                .ok_or_else(|| InventoryError::ItemNotFound(item.to_string()))?;

            if current < quantity {
                return Err(InventoryError::InsufficientStock {
                    item: item.to_string(),
                    available: current,
                    requested: quantity,
                });
            }
        }

        // Second pass: apply all decrements (safe because we hold the lock)
        let mut results = HashMap::new();
        for &(item, quantity) in items {
            let current = stock.get(item).copied().unwrap();
            let new_quantity = current - quantity;
            stock.insert(item.to_string(), new_quantity);
            results.insert(item.to_string(), new_quantity);
        }

        Ok(results)
    }

    /// Restock an item atomically.
    pub fn restock(&self, item: &str, quantity: u64) -> Result<u64, InventoryError> {
        let mut stock = self.stock.lock().map_err(|_| InventoryError::LockPoisoned)?;
        let entry = stock
            .get_mut(item)
            .ok_or_else(|| InventoryError::ItemNotFound(item.to_string()))?;
        *entry = entry.checked_add(quantity).unwrap_or(u64::MAX);
        Ok(*entry)
    }
}

fn main() {
    let inventory = InventorySystem::new();

    // Set up initial stock
    inventory.add_item("widget", 100).unwrap();
    inventory.add_item("gadget", 50).unwrap();

    println!("Initial stock - widget: {}, gadget: {}",
        inventory.get_stock("widget").unwrap(),
        inventory.get_stock("gadget").unwrap()
    );

    let num_threads = 20;
    let mut handles = Vec::new();

    for thread_id in 0..num_threads {
        let inv = inventory.clone();
        let handle = thread::spawn(move || {
            let item = if thread_id % 2 == 0 { "widget" } else { "gadget" };
            let quantity = (thread_id % 5) as u64 + 1;

            match inv.purchase(item, quantity) {
                Ok(remaining) => {
                    println!("Thread {}: Purchased {} of '{}'. Remaining: {}",
                        thread_id, quantity, item, remaining);
                    Ok((item.to_string(), quantity))
                }
                Err(e) => {
                    println!("Thread {}: Failed to purchase {} of '{}': {}",
                        thread_id, quantity, item, e);
                    Err(e)
                }
            }
        });
        handles.push(handle);
    }

    let mut total_widgets_sold: u64 = 0;
    let mut total_gadgets_sold: u64 = 0;

    for handle in handles {
        if let Ok(Ok((item, qty))) = handle.join() {
            match item.as_str() {
                "widget" => total_widgets_sold += qty,
                "gadget" => total_gadgets_sold += qty,
                _ => {}
            }
        }
    }

    let final_widgets = inventory.get_stock("widget").unwrap();
    let final_gadgets = inventory.get_stock("gadget").unwrap();

    println!("\n--- Final Report ---");
    println!("Widgets: started=100, sold={}, remaining={}, consistent={}",
        total_widgets_sold, final_widgets, 100 - total_widgets_sold == final_widgets);
    println!("Gadgets: started=50, sold={}, remaining={}, consistent={}",
        total_gadgets_sold, final_gadgets, 50 - total_gadgets_sold == final_gadgets);

    // Demonstrate multi-item transactional purchase
    inventory.add_item("bolt", 10).unwrap();
    inventory.add_item("nut", 10).unwrap();

    match inventory.purchase_multiple(&[("bolt", 5), ("nut", 5)]) {
        Ok(results) => println!("\nMulti-purchase succeeded: {:?}", results),
        Err(e) => println!("\nMulti-purchase failed: {}", e),
    }

    // This should fail atomically — neither item should be decremented
    match inventory.purchase_multiple(&[("bolt", 3), ("nut", 999)]) {
        Ok(_) => println!("Unexpected success"),
        Err(e) => {
            println!("Multi-purchase correctly failed: {}", e);
            println!("Bolt stock unchanged: {}", inventory.get_stock("bolt").unwrap());
            println!("Nut stock unchanged: {}", inventory.get_stock("nut").unwrap());
        }
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_basic_purchase() {
        let inv = InventorySystem::new();
        inv.add_item("item", 10).unwrap();
        assert_eq!(inv.purchase("item", 3).unwrap(), 7);
        assert_eq!(inv.get_stock("item").unwrap(), 7);
    }

    #[test]
    fn test_insufficient_stock() {
        let inv = InventorySystem::new();
        inv.add_item("item", 2).unwrap();
        let err = inv.purchase("item", 5).unwrap_err();
        assert_eq!(err, InventoryError::InsufficientStock {
            item: "item".to_string(),
            available: 2,
            requested: 5,
        });
        // Stock should be unchanged
        assert_eq!(inv.get_stock("item").unwrap(), 2);
    }

    #[test]
    fn test_item_not_found() {
        let inv = InventorySystem::new();
        let err = inv.purchase("nonexistent", 1).unwrap_err();
        assert_eq!(err, InventoryError::ItemNotFound("nonexistent".to_string()));
    }

    #[test]
    fn test_concurrent_no_oversell() {
        let inv = InventorySystem::new();
        inv.add_item("scarce", 10).unwrap();

        let mut handles = Vec::new();
        // 50 threads each trying to buy 1
        for _ in 0..50 {
            let inv_clone = inv.clone();
            handles.push(thread::spawn(move || {
                inv_clone.purchase("scarce", 1).is_ok()
            }));
        }

        let successes: usize = handles.into_iter()
            .map(|h| h.join().unwrap())
            .filter(|&ok| ok)
            .count();

        assert_eq!(successes, 10);
        assert_eq!(inv.get_stock("scarce").unwrap(), 0);
    }

    #[test]
    fn test_transactional_multi_purchase_rollback() {
        let inv = InventorySystem::new();
        inv.add_item("a", 5).unwrap();
        inv.add_item("b", 2).unwrap();

        // Should fail because b doesn't have enough
        assert!(inv.purchase_multiple(&[("a", 3), ("b", 5)]).is_err());

        // Neither should have changed
        assert_eq!(inv.get_stock("a").unwrap(), 5);
        assert_eq!(inv.get_stock("b").unwrap(), 2);
    }

    #[test]
    fn test_restock() {
        let inv = InventorySystem::new();
        inv.add_item("item", 5).unwrap();
        inv.purchase("item", 3).unwrap();
        assert_eq!(inv.restock("item", 10).unwrap(), 12);
    }
}